<div class="row g-4">
    <div class="col-lg-5"><div class="card border-0 shadow-sm"><div class="card-body p-4"><h2 class="h5">Novo showcase</h2><form method="post" action="/admin/showcases" class="row g-3"><?= \App\Core\Csrf::field() ?><div class="col-12"><label class="form-label">Pedido</label><select name="order_id" class="form-select"><?php foreach ($eligibleOrders as $order): ?><option value="<?= e((string) $order['id']) ?>">#<?= e((string) $order['id']) ?> - <?= e($order['client_name']) ?></option><?php endforeach; ?></select></div><div class="col-12"><label class="form-label">Imagem before</label><input type="text" name="before_image" class="form-control" placeholder="storage/uploads/original/..." required></div><div class="col-12"><label class="form-label">Imagem after</label><input type="text" name="after_image" class="form-control" placeholder="storage/uploads/edited/..." required></div><div class="col-12"><input type="text" name="title" class="form-control" placeholder="Título" required></div><div class="col-12"><textarea name="description" class="form-control" rows="4" placeholder="Descrição"></textarea></div><div class="col-md-6"><input type="number" name="sort_order" class="form-control" value="0"></div><div class="col-md-6"><div class="form-check mt-2"><input class="form-check-input" type="checkbox" name="is_featured" value="1" id="featured"><label class="form-check-label" for="featured">Destacar</label></div></div><div class="col-12"><button class="btn btn-dark w-100">Publicar showcase</button></div></form></div></div></div>
    <div class="col-lg-7"><div class="card border-0 shadow-sm"><div class="card-body p-4"><h2 class="h5">Showcases existentes</h2><table class="table align-middle"><thead><tr><th>Título</th><th>Pedido</th><th>Status</th><th></th></tr></thead><tbody><?php foreach ($showcases as $showcase): ?><tr><td><?= e($showcase['title']) ?></td><td>#<?= e((string) $showcase['order_id']) ?></td><td><?= $showcase['is_active'] ? 'Activo' : 'Inactivo' ?></td><td><form method="post" action="/admin/showcases/<?= e((string) $showcase['id']) ?>/toggle"><?= \App\Core\Csrf::field() ?><button class="btn btn-outline-dark btn-sm">Alternar</button></form></td></tr><?php endforeach; ?></tbody></table></div></div></div>
</div>
